dashboard.definition:
{
    "dataSources": {
        "ds_base_enriched": {
            "type": "ds.search",
            "options": {
                "query": "| rest splunk_server=local /services/apps/local | rename title as appid, label as app_label | fields appid app_label version disabled | join type=left appid [| inputlookup scan_splunkbase_apps | fields appid uid title type support is_archived archive_status app_version product_compatibility version_compatibility categories download_count updated_time] | join type=left appid [| rest splunk_server=local /servicesNS/-/-/configs/conf-products | eval appids=mvappend(addon, app_viz, app_viz_2) | mvexpand appids | eval appid=trim(appids) | where isnotnull(appid) AND appid!=\"\" | dedup appid | rename display_name as cisco_product, category as cisco_category | fields appid cisco_product cisco_category] | eval is_cisco=if(isnotnull(uid), \"Cisco Ecosystem\", \"Other\") | eval update_status=case(isnull(app_version), \"No Splunkbase Data\", version==app_version, \"Current\", 1==1, \"Update Available\") | eval app_health=case(is_archived==\"true\", \"Archived\", archive_status==\"archived_manually\", \"Deprecated\", disabled==\"1\", \"Disabled\", 1==1, \"Active\") | eval days_since_update=if(isnotnull(updated_time), round((now()-updated_time)/86400), null()) | eval staleness=case(isnull(days_since_update), \"Unknown\", days_since_update<=90, \"Fresh\", days_since_update<=365, \"Current\", days_since_update<=730, \"Aging\", 1==1, \"Stale\")",
                "queryParameters": {
                    "earliest": "-15m",
                    "latest": "now"
                }
            }
        },
        "ds_kpi_total": {
            "type": "ds.search",
            "options": {
                "query": "| stats count as total",
                "extend": "ds_base_enriched"
            }
        },
        "ds_kpi_cisco": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Cisco Ecosystem\" | stats count as total",
                "extend": "ds_base_enriched"
            }
        },
        "ds_kpi_other": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Other\" | stats count as total",
                "extend": "ds_base_enriched"
            }
        },
        "ds_kpi_updates": {
            "type": "ds.search",
            "options": {
                "query": "| search update_status=\"Update Available\" | stats count as total",
                "extend": "ds_base_enriched"
            }
        },
        "ds_kpi_archived": {
            "type": "ds.search",
            "options": {
                "query": "| search app_health=\"Archived\" OR app_health=\"Deprecated\" | stats count as total",
                "extend": "ds_base_enriched"
            }
        },
        "ds_pie_ecosystem": {
            "type": "ds.search",
            "options": {
                "query": "| stats count by is_cisco",
                "extend": "ds_base_enriched"
            }
        },
        "ds_bar_support": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Cisco Ecosystem\" | stats count by support | sort - count",
                "extend": "ds_base_enriched"
            }
        },
        "ds_col_update": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Cisco Ecosystem\" | stats count by update_status",
                "extend": "ds_base_enriched"
            }
        },
        "ds_col_staleness": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Cisco Ecosystem\" | stats count by staleness",
                "extend": "ds_base_enriched"
            }
        },
        "ds_table_cisco": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Cisco Ecosystem\" | rename appid as AppID, app_label as Name, cisco_product as Product, cisco_category as Category, version as Installed, app_version as Latest, update_status as UpdateStatus, app_health as Health, days_since_update as DaysSince | table AppID Name Product Category type support Installed Latest UpdateStatus Health staleness DaysSince | sort 0 type support AppID",
                "extend": "ds_base_enriched"
            }
        },
        "ds_table_updates": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Cisco Ecosystem\" AND update_status=\"Update Available\" | eval version_gap=version.\" → \".app_version | rename appid as AppID, app_label as Name, cisco_product as Product, support as Support, version as Installed, app_version as Latest, version_gap as Migration, days_since_update as DaysSince | table AppID Name Product Support Installed Latest Migration DaysSince | sort 0 Support AppID",
                "extend": "ds_base_enriched"
            }
        },
        "ds_bar_type": {
            "type": "ds.search",
            "options": {
                "query": "| search is_cisco=\"Cisco Ecosystem\" | stats count by type | sort - count",
                "extend": "ds_base_enriched"
            }
        },
        "ds_base_catalog": {
            "type": "ds.search",
            "options": {
                "query": "| rest splunk_server=local /servicesNS/-/-/configs/conf-products | rename eai:acl.app as app | where app=\"splunk-cisco-app-navigator\" | fields title display_name category status support_level addon addon_label sourcetypes ai_enabled secure_networking_gtm soar_connector_label itsi_content_pack_label alert_action_label",
                "queryParameters": {
                    "earliest": "-15m",
                    "latest": "now"
                }
            }
        },
        "ds_pie_catalog_cat": {
            "type": "ds.search",
            "options": {
                "query": "| stats count by category | sort - count",
                "extend": "ds_base_catalog"
            }
        },
        "ds_col_catalog_status": {
            "type": "ds.search",
            "options": {
                "query": "| stats count by status | sort - count",
                "extend": "ds_base_catalog"
            }
        },
        "ds_col_catalog_support": {
            "type": "ds.search",
            "options": {
                "query": "| stats count by support_level | sort - count",
                "extend": "ds_base_catalog"
            }
        },
        "ds_kpi_catalog_total": {
            "type": "ds.search",
            "options": {
                "query": "| stats count as total",
                "extend": "ds_base_catalog"
            }
        },
        "ds_kpi_catalog_active": {
            "type": "ds.search",
            "options": {
                "query": "| search status=\"active\" | stats count as total",
                "extend": "ds_base_catalog"
            }
        },
        "ds_kpi_catalog_soar": {
            "type": "ds.search",
            "options": {
                "query": "| where isnotnull(soar_connector_label) AND soar_connector_label!=\"\" | stats count as total",
                "extend": "ds_base_catalog"
            }
        },
        "ds_kpi_catalog_ai": {
            "type": "ds.search",
            "options": {
                "query": "| search ai_enabled=\"true\" OR ai_enabled=\"1\" | stats count as total",
                "extend": "ds_base_catalog"
            }
        }
    },
    "defaults": {
        "dataSources": {
            "ds.search": {
                "options": {
                    "queryParameters": {
                        "earliest": "-15m",
                        "latest": "now"
                    }
                }
            }
        }
    },
    "inputs": {},
    "layout": {
        "type": "absolute",
        "options": {
            "display": "auto-scale",
            "width": 1440,
            "height": 3200
        },
        "structure": [
            {
                "item": "viz_header_overview",
                "type": "block",
                "position": { "x": 20, "y": 10, "w": 1400, "h": 60 }
            },
            {
                "item": "viz_kpi_total",
                "type": "block",
                "position": { "x": 20, "y": 80, "w": 268, "h": 120 }
            },
            {
                "item": "viz_kpi_cisco",
                "type": "block",
                "position": { "x": 298, "y": 80, "w": 268, "h": 120 }
            },
            {
                "item": "viz_kpi_other",
                "type": "block",
