            },
            {
                "item": "viz_header_health",
                "type": "block",
                "position": { "x": 20, "y": 650, "w": 1400, "h": 50 }
            },
            {
                "item": "viz_col_update",
                "type": "block",
                "position": { "x": 20, "y": 710, "w": 460, "h": 350 }
            },
            {
                "item": "viz_col_staleness",
                "type": "block",
                "position": { "x": 500, "y": 710, "w": 460, "h": 350 }
            },
            {
                "item": "viz_bar_type",
                "type": "block",
                "position": { "x": 980, "y": 710, "w": 440, "h": 350 }
            },
            {
                "item": "viz_header_inventory",
                "type": "block",
                "position": { "x": 20, "y": 1080, "w": 1400, "h": 50 }
            },
            {
                "item": "viz_table_cisco",
                "type": "block",
                "position": { "x": 20, "y": 1140, "w": 1400, "h": 500 }
            },
            {
                "item": "viz_header_updates",
                "type": "block",
                "position": { "x": 20, "y": 1660, "w": 1400, "h": 50 }
            },
            {
                "item": "viz_table_updates",
                "type": "block",
                "position": { "x": 20, "y": 1720, "w": 1400, "h": 400 }
            },
            {
                "item": "viz_header_catalog",
                "type": "block",
                "position": { "x": 20, "y": 2140, "w": 1400, "h": 60 }
            },
            {
                "item": "viz_kpi_cat_total",
                "type": "block",
                "position": { "x": 20, "y": 2210, "w": 340, "h": 120 }
            },
            {
                "item": "viz_kpi_cat_active",
                "type": "block",
                "position": { "x": 380, "y": 2210, "w": 340, "h": 120 }
            },
            {
                "item": "viz_kpi_cat_soar",
                "type": "block",
                "position": { "x": 740, "y": 2210, "w": 340, "h": 120 }
            },
            {
                "item": "viz_kpi_cat_ai",
                "type": "block",
                "position": { "x": 1100, "y": 2210, "w": 320, "h": 120 }
            },
            {
                "item": "viz_pie_catalog_cat",
                "type": "block",
                "position": { "x": 20, "y": 2350, "w": 460, "h": 380 }
            },
            {
                "item": "viz_col_catalog_status",
                "type": "block",
                "position": { "x": 500, "y": 2350, "w": 460, "h": 380 }
            },
            {
                "item": "viz_col_catalog_support",
                "type": "block",
                "position": { "x": 980, "y": 2350, "w": 440, "h": 380 }
            }
        ],
        "globalInputs": []
    },
    "visualizations": {
        "viz_header_overview": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "## 🔍 Splunk Instance — App Inventory\nAll installed apps cross-referenced with the Splunkbase catalog and SCAN product catalog"
            }
        },
        "viz_kpi_total": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_total"
            },
            "title": "Total Installed Apps",
            "options": {
                "majorColor": "#333333",
                "backgroundColor": "#f4f5f7",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "apps",
                "unitPosition": "after"
            }
        },
        "viz_kpi_cisco": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_cisco"
            },
            "title": "Cisco Ecosystem Apps",
            "options": {
                "majorColor": "#049fd9",
                "backgroundColor": "#e8f6fc",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "apps",
                "unitPosition": "after"
            }
        },
        "viz_kpi_other": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_other"
            },
            "title": "Non-Cisco Apps",
            "options": {
                "majorColor": "#6B7280",
                "backgroundColor": "#f0f0f2",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "apps",
                "unitPosition": "after"
            }
        },
        "viz_kpi_updates": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_updates"
            },
            "title": "Updates Available",
            "options": {
                "majorColor": "#d97706",
                "backgroundColor": "#fef3c7",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "apps",
                "unitPosition": "after"
            }
        },
        "viz_kpi_archived": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_archived"
            },
            "title": "Archived / Deprecated",
            "options": {
                "majorColor": "#dc2626",
                "backgroundColor": "#fef2f2",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "installed",
                "unitPosition": "after"
            }
        },
        "viz_header_breakdown": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "## 📊 Ecosystem Breakdown\nCisco Ecosystem vs Other installed apps · Support level distribution"
            }
        },
        "viz_pie_ecosystem": {
            "type": "splunk.pie",
            "dataSources": {
                "primary": "ds_pie_ecosystem"
            },
            "title": "Cisco Ecosystem vs Other",
            "options": {
                "showDonutHole": true,
                "seriesColors": ["#049fd9", "#94bec4"]
            }
        },
        "viz_bar_support": {
            "type": "splunk.column",
            "dataSources": {
                "primary": "ds_bar_support"
            },
            "title": "Support Level (Cisco Apps Only)",
            "options": {
                "xAxisTitleVisibility": "hide",
                "yAxisTitleVisibility": "hide",
                "seriesColors": ["#049fd9"],
                "dataValuesDisplay": "all"
            }
        },
        "viz_header_health": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "## 🩺 Version & Update Health\nAre your Cisco apps current? How fresh are the Splunkbase releases?"
            }
        },
        "viz_col_update": {
            "type": "splunk.column",
            "dataSources": {
                "primary": "ds_col_update"
            },
            "title": "Update Status",
            "options": {
                "xAxisTitleVisibility": "hide",
                "yAxisTitleVisibility": "hide",
                "seriesColors": ["#049fd9"],
                "dataValuesDisplay": "all"
            }
        },
        "viz_col_staleness": {
            "type": "splunk.column",
            "dataSources": {
                "primary": "ds_col_staleness"
            },
            "title": "App Freshness",
            "options": {
                "xAxisTitleVisibility": "hide",
                "yAxisTitleVisibility": "hide",
                "seriesColors": ["#049fd9"],
                "dataValuesDisplay": "all"
            }
        },
        "viz_bar_type": {
            "type": "splunk.column",
            "dataSources": {
                "primary": "ds_bar_type"
            },
            "title": "By App Type",
            "options": {
                "xAxisTitleVisibility": "hide",
                "yAxisTitleVisibility": "hide",
                "seriesColors": ["#049fd9"],
                "dataValuesDisplay": "all"
            }
        },
        "viz_header_inventory": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "## 📋 Cisco App Inventory\nEvery installed Cisco ecosystem app — enriched with Splunkbase intelligence and product catalog mapping"
            }
        },
        "viz_table_cisco": {
            "type": "splunk.table",
            "dataSources": {
                "primary": "ds_table_cisco"
            },
            "title": "Installed Cisco Ecosystem Apps",
            "options": {
                "count": 50,
                "dataOverlayMode": "none",
                "drilldown": "none",
                "showRowNumbers": true,
                "tableFormat": {
                    "rowBackgroundColors": "> table | seriesByIndex(0) | pick(#f4f8fb,#ffffff)",
                    "headerBackgroundColor": "#049fd9",
                    "headerFontColor": "#ffffff"
                }
            }
        },
        "viz_header_updates": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "## ⚠️ Apps Needing Update\nCisco ecosystem apps with newer versions available on Splunkbase"
            }
        },
        "viz_table_updates": {
            "type": "splunk.table",
            "dataSources": {
                "primary": "ds_table_updates"
            },
            "title": "Update Required — Version Comparison",
            "options": {
                "count": 50,
                "dataOverlayMode": "none",
                "drilldown": "none",
                "showRowNumbers": true,
                "tableFormat": {
                    "rowBackgroundColors": "> table | seriesByIndex(0) | pick(#fef3c7,#ffffff)",
                    "headerBackgroundColor": "#d97706",
                    "headerFontColor": "#ffffff"
                }
            }
        },
        "viz_header_catalog": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "## 🛡️ Product Catalog Intelligence\nSCAN product catalog analysis — 79 Cisco products across Security, Networking, Observability, and Collaboration"
            }
        },
        "viz_kpi_cat_total": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_catalog_total"
            },
            "title": "Total Products",
            "options": {
                "majorColor": "#049fd9",
                "backgroundColor": "#e8f6fc",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "products",
                "unitPosition": "after"
            }
        },
        "viz_kpi_cat_active": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_catalog_active"
            },
            "title": "Active Products",
            "options": {
                "majorColor": "#16a34a",
                "backgroundColor": "#f0fdf4",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "active",
                "unitPosition": "after"
            }
        },
        "viz_kpi_cat_soar": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_catalog_soar"
            },
            "title": "SOAR Connectors",
            "options": {
                "majorColor": "#7c3aed",
                "backgroundColor": "#f5f3ff",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "products",
                "unitPosition": "after"
            }
        },
        "viz_kpi_cat_ai": {
            "type": "splunk.singlevalue",
            "dataSources": {
                "primary": "ds_kpi_catalog_ai"
            },
            "title": "AI-Powered",
            "options": {
                "majorColor": "#0891b2",
                "backgroundColor": "#ecfeff",
                "sparklineDisplay": "off",
                "trendDisplay": "off",
                "unit": "products",
                "unitPosition": "after"
            }
        },
        "viz_pie_catalog_cat": {
            "type": "splunk.pie",
            "dataSources": {
                "primary": "ds_pie_catalog_cat"
            },
            "title": "Products by Category",
            "options": {
                "showDonutHole": true,
                "seriesColors": ["#0284c7", "#16a34a", "#7c3aed", "#d97706"]
            }
        },
        "viz_col_catalog_status": {
            "type": "splunk.column",
            "dataSources": {
                "primary": "ds_col_catalog_status"
            },
            "title": "Products by Status",
            "options": {
                "xAxisTitleVisibility": "hide",
                "yAxisTitleVisibility": "hide",
                "seriesColors": ["#049fd9"],
                "dataValuesDisplay": "all"
            }
        },
        "viz_col_catalog_support": {
            "type": "splunk.column",
            "dataSources": {
                "primary": "ds_col_catalog_support"
            },
            "title": "Products by Support Level",
            "options": {
                "xAxisTitleVisibility": "hide",
                "yAxisTitleVisibility": "hide",
                "seriesColors": ["#049fd9"],
                "dataValuesDisplay": "all"
            }
        }
    },
    "title": "Cisco Ecosystem Intelligence",
    "description": "Comprehensive analysis of installed Cisco apps, version health, update status, and Splunkbase intelligence — enriched with product catalog data"
}
